// src/main/java/com/eventstreaming/producer/EventProducer.java
package com.eventstreaming.producer;

import com.eventstreaming.model.Event;
import com.eventstreaming.model.OrderEvent;
import com.eventstreaming.model.UserEvent;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.kafka.support.SendResult;
import org.springframework.stereotype.Service;

import java.util.concurrent.CompletableFuture;

@Service
public class EventProducer {

    private static final Logger logger = LoggerFactory.getLogger(EventProducer.class);

    private static final String USER_EVENTS_TOPIC = "user-events";
    private static final String ORDER_EVENTS_TOPIC = "order-events";
    private static final String NOTIFICATION_EVENTS_TOPIC = "notification-events";

    private final KafkaTemplate<String, Object> kafkaTemplate;

    public EventProducer(KafkaTemplate<String, Object> kafkaTemplate) {
        this.kafkaTemplate = kafkaTemplate;
    }

    public void publishUserEvent(UserEvent userEvent) {
        logger.info("Publishing user event: {}", userEvent);
        CompletableFuture<SendResult<String, Object>> future =
                kafkaTemplate.send(USER_EVENTS_TOPIC, userEvent.getUserId(), userEvent);

        future.whenComplete((result, ex) -> {
            if (ex == null) {
                logger.info("User event sent successfully: topic={}, partition={}, offset={}",
                        result.getRecordMetadata().topic(),
                        result.getRecordMetadata().partition(),
                        result.getRecordMetadata().offset());
            } else {
                logger.error("Failed to send user event: {}", ex.getMessage(), ex);
            }
        });
    }

    public void publishOrderEvent(OrderEvent orderEvent) {
        logger.info("Publishing order event: {}", orderEvent);
        CompletableFuture<SendResult<String, Object>> future =
                kafkaTemplate.send(ORDER_EVENTS_TOPIC, orderEvent.getOrderId(), orderEvent);

        future.whenComplete((result, ex) -> {
            if (ex == null) {
                logger.info("Order event sent successfully: topic={}, partition={}, offset={}",
                        result.getRecordMetadata().topic(),
                        result.getRecordMetadata().partition(),
                        result.getRecordMetadata().offset());
            } else {
                logger.error("Failed to send order event: {}", ex.getMessage(), ex);
            }
        });
    }

    public void publishNotificationEvent(Event event) {
        logger.info("Publishing notification event: {}", event);
        CompletableFuture<SendResult<String, Object>> future =
                kafkaTemplate.send(NOTIFICATION_EVENTS_TOPIC, event.getEventId(), event);

        future.whenComplete((result, ex) -> {
            if (ex == null) {
                logger.info("Notification event sent successfully: topic={}, partition={}, offset={}",
                        result.getRecordMetadata().topic(),
                        result.getRecordMetadata().partition(),
                        result.getRecordMetadata().offset());
            } else {
                logger.error("Failed to send notification event: {}", ex.getMessage(), ex);
            }
        });
    }

    public void publishToTopic(String topic, String key, Object message) {
        logger.info("Publishing message to topic {}: key={}", topic, key);
        CompletableFuture<SendResult<String, Object>> future =
                kafkaTemplate.send(topic, key, message);

        future.whenComplete((result, ex) -> {
            if (ex == null) {
                logger.info("Message sent successfully to topic={}, partition={}, offset={}",
                        result.getRecordMetadata().topic(),
                        result.getRecordMetadata().partition(),
                        result.getRecordMetadata().offset());
            } else {
                logger.error("Failed to send message to topic {}: {}", topic, ex.getMessage(), ex);
            }
        });
    }
}

