package com.eventstreaming.consumer;

import com.eventstreaming.model.UserEvent;
import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.kafka.support.Acknowledgment;
import org.springframework.kafka.support.KafkaHeaders;
import org.springframework.messaging.handler.annotation.Header;
import org.springframework.messaging.handler.annotation.Payload;
import org.springframework.stereotype.Service;

@Service
public class UserEventConsumer {

    private static final Logger logger = LoggerFactory.getLogger(UserEventConsumer.class);

    @KafkaListener(
            topics = "user-events",
            groupId = "event-streaming-group",
            containerFactory = "kafkaListenerContainerFactory"
    )
    public void consumeUserEvent(
            @Payload UserEvent userEvent,
            @Header(KafkaHeaders.RECEIVED_TOPIC) String topic,
            @Header(KafkaHeaders.RECEIVED_PARTITION) int partition,
            @Header(KafkaHeaders.OFFSET) long offset,
            @Header(KafkaHeaders.RECEIVED_KEY) String key) {

        logger.info("Received user event: topic={}, partition={}, offset={}, key={}",
                topic, partition, offset, key);
        logger.info("User event details: {}", userEvent);

        processUserEvent(userEvent);
    }

    private void processUserEvent(UserEvent userEvent) {
        switch (userEvent.getAction()) {
            case "CREATED":
                logger.info("Processing new user creation: userId={}, username={}",
                        userEvent.getUserId(), userEvent.getUsername());
                break;
            case "UPDATED":
                logger.info("Processing user update: userId={}", userEvent.getUserId());
                break;
            case "DELETED":
                logger.info("Processing user deletion: userId={}", userEvent.getUserId());
                break;
            default:
                logger.warn("Unknown user action: {}", userEvent.getAction());
        }
    }
}

