package com.eventstreaming.consumer;

import com.eventstreaming.model.Event;
import com.eventstreaming.model.OrderEvent;
import com.eventstreaming.producer.EventProducer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.kafka.support.KafkaHeaders;
import org.springframework.messaging.handler.annotation.Header;
import org.springframework.messaging.handler.annotation.Payload;
import org.springframework.stereotype.Service;

import java.util.HashMap;
import java.util.Map;

@Service
public class OrderEventConsumer {

    private static final Logger logger = LoggerFactory.getLogger(OrderEventConsumer.class);

    private final EventProducer eventProducer;

    public OrderEventConsumer(EventProducer eventProducer) {
        this.eventProducer = eventProducer;
    }

    @KafkaListener(
            topics = "order-events",
            groupId = "event-streaming-group",
            containerFactory = "kafkaListenerContainerFactory"
    )
    public void consumeOrderEvent(
            @Payload OrderEvent orderEvent,
            @Header(KafkaHeaders.RECEIVED_TOPIC) String topic,
            @Header(KafkaHeaders.RECEIVED_PARTITION) int partition,
            @Header(KafkaHeaders.OFFSET) long offset) {

        logger.info("Received order event: topic={}, partition={}, offset={}", topic, partition, offset);
        logger.info("Order event details: {}", orderEvent);

        processOrderEvent(orderEvent);
    }

    private void processOrderEvent(OrderEvent orderEvent) {
        logger.info("Processing order: orderId={}, status={}", orderEvent.getOrderId(), orderEvent.getStatus());

        // After processing, publish a notification event
        Map<String, Object> notificationPayload = new HashMap<>();
        notificationPayload.put("orderId", orderEvent.getOrderId());
        notificationPayload.put("userId", orderEvent.getUserId());
        notificationPayload.put("message", "Order " + orderEvent.getOrderId() + " has been " + orderEvent.getStatus());

        Event notificationEvent = new Event("ORDER_NOTIFICATION", "order-service", notificationPayload);
        eventProducer.publishNotificationEvent(notificationEvent);
    }
}

