package com.eventstreaming.controller;

import com.eventstreaming.model.Event;
import com.eventstreaming.model.OrderEvent;
import com.eventstreaming.model.UserEvent;
import com.eventstreaming.producer.EventProducer;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.math.BigDecimal;
import java.util.HashMap;
import java.util.Map;
import java.util.UUID;

@RestController
@RequestMapping("/api/events")
public class EventController {

    private final EventProducer eventProducer;

    public EventController(EventProducer eventProducer) {
        this.eventProducer = eventProducer;
    }

    @PostMapping("/users")
    public ResponseEntity<Map<String, String>> publishUserEvent(@RequestBody UserEvent userEvent) {
        if (userEvent.getUserId() == null || userEvent.getUserId().isEmpty()) {
            userEvent.setUserId(UUID.randomUUID().toString());
        }
        eventProducer.publishUserEvent(userEvent);

        Map<String, String> response = new HashMap<>();
        response.put("status", "User event published successfully");
        response.put("userId", userEvent.getUserId());
        return ResponseEntity.status(HttpStatus.CREATED).body(response);
    }

    @PostMapping("/orders")
    public ResponseEntity<Map<String, String>> publishOrderEvent(@RequestBody OrderEvent orderEvent) {
        if (orderEvent.getOrderId() == null || orderEvent.getOrderId().isEmpty()) {
            orderEvent.setOrderId(UUID.randomUUID().toString());
        }
        eventProducer.publishOrderEvent(orderEvent);

        Map<String, String> response = new HashMap<>();
        response.put("status", "Order event published successfully");
        response.put("orderId", orderEvent.getOrderId());
        return ResponseEntity.status(HttpStatus.CREATED).body(response);
    }

    @PostMapping("/notifications")
    public ResponseEntity<Map<String, String>> publishNotificationEvent(@RequestBody Event event) {
        eventProducer.publishNotificationEvent(event);

        Map<String, String> response = new HashMap<>();
        response.put("status", "Notification event published successfully");
        response.put("eventId", event.getEventId());
        return ResponseEntity.status(HttpStatus.CREATED).body(response);
    }

    @PostMapping("/custom/{topic}")
    public ResponseEntity<Map<String, String>> publishCustomEvent(
            @PathVariable String topic,
            @RequestParam(required = false) String key,
            @RequestBody Map<String, Object> message) {

        String messageKey = (key != null) ? key : UUID.randomUUID().toString();
        eventProducer.publishToTopic(topic, messageKey, message);

        Map<String, String> response = new HashMap<>();
        response.put("status", "Custom event published successfully");
        response.put("topic", topic);
        response.put("key", messageKey);
        return ResponseEntity.status(HttpStatus.CREATED).body(response);
    }

    // Test endpoint to publish sample events
    @PostMapping("/test/sample")
    public ResponseEntity<Map<String, String>> publishSampleEvents() {
        // Sample user event
        UserEvent userEvent = new UserEvent(
                UUID.randomUUID().toString(),
                "johndoe",
                "john.doe@example.com",
                "CREATED"
        );
        eventProducer.publishUserEvent(userEvent);

        // Sample order event
        OrderEvent orderEvent = new OrderEvent(
                UUID.randomUUID().toString(),
                userEvent.getUserId(),
                "Laptop Pro 15",
                1,
                new BigDecimal("1299.99"),
                "PLACED"
        );
        eventProducer.publishOrderEvent(orderEvent);

        // Sample notification event
        Map<String, Object> payload = new HashMap<>();
        payload.put("message", "Welcome to our platform!");
        payload.put("userId", userEvent.getUserId());
        Event notificationEvent = new Event("WELCOME_NOTIFICATION", "api-gateway", payload);
        eventProducer.publishNotificationEvent(notificationEvent);

        Map<String, String> response = new HashMap<>();
        response.put("status", "Sample events published successfully");
        response.put("userId", userEvent.getUserId());
        response.put("orderId", orderEvent.getOrderId());
        response.put("notificationEventId", notificationEvent.getEventId());
        return ResponseEntity.status(HttpStatus.CREATED).body(response);
    }
}

